import{_ as r,o as i,c as n,ag as a,j as e,a as t}from"./chunks/framework.NIzFHKo_.js";const h=JSON.parse('{"title":"ADR-0007: Unified Front Matter and Progressive Documentation Topology","description":"","frontmatter":{"layout":"adr ... ...","title":"ADR-0007: Unified Front Matter and Progressive Documentation Topology","slug":"adr-0007-unified-front-matter-and-progressive-doc-topology ... ...","summary":"Adopts one universal front matter schema with layout-based meaning, canonical field ordering, and a second-layer documentation topology so blueprint sections read progressively instead of as flat page buckets. ... ...","status":"proposed","created_at":"2026-04-01T00:00:00.000Z","updated_at":"2026-04-01T00:00:00.000Z","author":"Cody / AI ... ...","owner":"Cody ... ...","sensitivity":"internal ... ...","classification":"business_internal ... ...","realm_label":"","context":"The blueprint has grown large enough that flat section folders are creating navigation friction. Prior front matter attempts also produced overlapping taxonomies, retired ontology fields, and drift between human-readable metadata and canonical system truth. ... ...","aliases":[],"tags":["governance","front-matter","documentation","templates","topology"],"keywords":["front matter","layout","templates","doc structure","blueprint topology"],"references":[],"target_system":"QiOS Master Blueprint","target_scope":"docs, templates, standards, scripts, mkdocs navigation ... ...","canonical_ref":"","uid":"","template_key":["adr-template"],"source_type":"manual ... ...","adr_id":"ADR-0007 ... ...","supersedes":"","artifact_kind":"","registry_key":"","standard_key":""},"headers":[],"relativePath":"10_core/10_governance/50_decisions/adr-0007_unified_front_matter_and_progressive_doc_topology.md","filePath":"10_core/10_governance/50_decisions/adr-0007_unified_front_matter_and_progressive_doc_topology.md"}'),d={name:"10_core/10_governance/50_decisions/adr-0007_unified_front_matter_and_progressive_doc_topology.md"};function l(s,o,c,u,m,p){return i(),n("div",null,[...o[0]||(o[0]=[a('<h1 id="adr-0007-unified-front-matter-and-progressive-documentation-topology" tabindex="-1">ADR-0007: Unified Front Matter and Progressive Documentation Topology <a class="header-anchor" href="#adr-0007-unified-front-matter-and-progressive-documentation-topology" aria-label="Permalink to &quot;ADR-0007: Unified Front Matter and Progressive Documentation Topology&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Proposed</p><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>The blueprint documentation has expanded beyond a comfortable flat structure. Several sections now contain enough material that readers must hop between sibling pages without a clear progressive path.</p>',5),e("p",{index:"2"},[t("At the same time, earlier front matter systems introduced overlapping and now-retired concepts such as "),e("code",null,"qid"),t(", "),e("code",null,"qi_decimal"),t(", graph-poetry attributes, and realm-driven structural meaning. The current blueprint doctrine already establishes that front matter is supportive metadata only, not the system of record, and that canonical truth comes from governed system layers rather than file headers. :contentReference[oaicite:1]{index=1} :contentReference[oaicite:2]")],-1),a('<p>A unified, lean, enforceable front matter profile is required, along with a documentation topology that preserves reading order and reduces cognitive load.</p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>QiOS adopts the following documentation and metadata rules:</p><ol><li><p><strong>Universal Front Matter Vocabulary</strong></p><ul><li>All markdown documentation within the blueprint uses one shared front matter vocabulary.</li><li>The <code>layout</code> field determines document intent and conditional requirements.</li><li>Required fields may vary by <code>layout</code>, but the field vocabulary remains singular.</li></ul></li><li><p><strong>Front Matter Is Supportive Metadata Only</strong></p><ul><li>Front matter does not issue canonical identity.</li><li>Front matter does not define schema placement, routing truth, or graph truth.</li><li>Legacy fields tied to retired identity/ontology models are removed from active doctrine.</li></ul></li><li><p><strong>Canonical Field Order</strong></p><ul><li>Front matter fields must appear in a governed order.</li><li>Fields are grouped into human-readable sections.</li><li>A formatter/linter will normalize order and validate layout-specific requirements.</li></ul></li><li><p><strong>Progressive Documentation Topology</strong></p><ul><li>Each major blueprint section may contain ordered subfolders.</li><li>Subfolders must support a progressive reading path from overview to model to rules to reference.</li><li>Documentation should read linearly within a section rather than as a flat bucket of peer pages.</li></ul></li><li><p><strong>Canonical Source Separation</strong></p><ul><li><code>docs/</code> remains the rendered doctrine layer.</li><li><code>standards/</code>, <code>registry/</code>, <code>adr/</code>, and <code>schemas/</code> remain canonical source layers outside <code>docs/</code>.</li><li>The documentation site may render or summarize those sources through pages in <code>docs/</code>, but they do not move into <code>docs/</code> merely for visibility.</li></ul></li></ol><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>Reduces front matter drift and overlapping taxonomies.</li><li>Makes documentation easier to read in sequence.</li><li>Preserves separation between rendered doctrine and machine-readable source-of-truth files.</li><li>Creates a stable template and validation model for future growth.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>Existing docs will need normalization and partial folder moves.</li><li>MkDocs navigation must be updated to reflect second-layer section structure.</li><li>Some legacy front matter fields and earlier taxonomy experiments will be formally retired.</li></ul><h2 id="affected-documents" tabindex="-1">Affected Documents <a class="header-anchor" href="#affected-documents" aria-label="Permalink to &quot;Affected Documents&quot;">​</a></h2><ul><li><code>standards/content_metadata_profile.yaml</code></li><li><code>standards/metadata_rules.yaml</code></li><li><code>templates/page_template.md</code></li><li><code>templates/adr_template.md</code></li><li><code>templates/artifact_template.md</code></li><li><code>scripts/normalize_front_matter.py</code></li><li><code>mkdocs.yml</code></li><li><code>docs/01_governance/*</code></li><li><code>docs/02_architecture/*</code></li><li><code>docs/03_structure/*</code></li><li><code>docs/04_data/*</code></li><li><code>docs/05_compute/*</code></li><li><code>docs/06_applications/*</code></li><li><code>docs/07_operations/*</code></li></ul>',11)])])}const _=r(d,[["render",l]]);export{h as __pageData,_ as default};
